class Solution:
    def primePalindrome(self, n: int) -> int:
        def is_prime(num):
            if num < 2:
                return False
            for i in range(2, int(num**0.5) + 1):
                if num % i == 0:
                    return False
            return True

        if n < 2:
            return 2

        while True:
            if str(n) == str(n)[::-1] and is_prime(n):
                return n
            n += 1
```

